import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getDashboardStats } from '../../services/dataService';
import { formatCurrency } from '../../utils/helpers';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { FiHome, FiUsers, FiDollarSign, FiFileText, FiTool, FiMessageSquare } from 'react-icons/fi';

const AdminDashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getDashboardStats();
        setStats(res.data.data);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    fetch();
  }, []);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header"><h1>Dashboard</h1></div>

      <div className="stats-grid">
        <Link to="/admin/properties" className="stat-card" style={{ textDecoration: 'none' }}>
          <FiHome size={24} color="var(--primary-color)" />
          <div className="stat-value">{stats?.properties?.total || 0}</div>
          <div className="stat-label">Total Properties</div>
        </Link>
        <Link to="/admin/customers" className="stat-card" style={{ textDecoration: 'none' }}>
          <FiUsers size={24} color="var(--success-color)" />
          <div className="stat-value">{stats?.users?.customers || 0}</div>
          <div className="stat-label">Total Customers</div>
        </Link>
        <Link to="/admin/payments" className="stat-card" style={{ textDecoration: 'none' }}>
          <FiDollarSign size={24} color="var(--warning-color)" />
          <div className="stat-value">{formatCurrency(stats?.financial?.totalRevenue || 0)}</div>
          <div className="stat-label">Total Revenue</div>
        </Link>
        <Link to="/admin/purchase-requests" className="stat-card" style={{ textDecoration: 'none' }}>
          <FiFileText size={24} color="var(--info-color)" />
          <div className="stat-value">{stats?.pendingActions?.purchaseRequests || 0}</div>
          <div className="stat-label">Pending Requests</div>
        </Link>
        <Link to="/admin/payments" className="stat-card" style={{ textDecoration: 'none' }}>
          <FiDollarSign size={24} color="var(--danger-color)" />
          <div className="stat-value">{stats?.pendingActions?.payments || 0}</div>
          <div className="stat-label">Pending Payments</div>
        </Link>
        <Link to="/admin/change-requests" className="stat-card" style={{ textDecoration: 'none' }}>
          <FiTool size={24} color="#6f42c1" />
          <div className="stat-value">{stats?.pendingActions?.changeRequests || 0}</div>
          <div className="stat-label">Change Requests</div>
        </Link>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px', marginTop: '24px' }}>
        <div className="card">
          <h3>Property Status</h3>
          <div className="detail-grid">
            <div><span className="detail-label">Available</span><span>{stats?.properties?.available || 0}</span></div>
            <div><span className="detail-label">Sold</span><span>{stats?.properties?.sold || 0}</span></div>
            <div><span className="detail-label">Reserved</span><span>{stats?.properties?.reserved || 0}</span></div>
          </div>
        </div>

        <div className="card">
          <h3>Recent Payments</h3>
          {stats?.recentPayments && stats.recentPayments.length > 0 ? (
            <ul style={{ listStyle: 'none', padding: 0 }}>
              {stats.recentPayments.map((p, i) => (
                <li key={i} style={{ padding: '8px 0', borderBottom: '1px solid #eee' }}>
                  {p.customer?.name} - {formatCurrency(p.amount)} ({p.property?.title})
                </li>
              ))}
            </ul>
          ) : <p>No recent payments</p>}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
